import { useEffect, useState } from "react";
import axios from "axios";

export default function CompliancePanel() {
  const [compliance, setCompliance] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchCompliance = async () => {
      setLoading(true);
      setError("");
      try {
        const res = await axios.get("http://localhost:5000/api/compliance");
        setCompliance(res.data);
      } catch (err) {
        setError("Failed to load compliance status.");
      }
      setLoading(false);
    };
    fetchCompliance();
  }, []);

  return (
    <div className="card compliance-card">
      <h3>🏥 Hospital Compliance Panel</h3>
      {loading && <p>Loading...</p>}
      {error && <p className="error">{error}</p>}
      {compliance && (
        <>
          <p>
            <b>Status:</b> {compliance.status === "Compliant" ? <span style={{color: 'green'}}>✅ Compliant</span> : <span style={{color: 'orange'}}>⚠️ Warning</span>}
          </p>
          <div>
            <b>Audit Log:</b>
            <div className="audit-log">
              {compliance.auditLog.length === 0 && <p>No audit records.</p>}
              {compliance.auditLog.map((log, idx) => (
                <div key={idx} className="audit-item">
                  <span>{log.action}</span> | <span>{log.type}</span> | <span>{new Date(log.time).toLocaleString()}</span>
                </div>
              ))}
            </div>
          </div>
          <button className="report-btn" onClick={() => alert('Compliance Report Generated (UI only)')}>Generate Compliance Report</button>
        </>
      )}
    </div>
  );
}
